12	class RequestLoggingMiddleware
13	{
14	    public function handle(Request $request, Closure $next): Response
15	    {
16	        $startTime = microtime(true);
17	
18	        $response = $next($request);
19	
20	        $duration = round((microtime(true) - $startTime) * 1000, 2);
21	
22	        Log::channel('daily')->info('request', [
23	            'trace_id' => $request->attributes->get('trace_id', 'unknown'),
24	            'method' => $request->method(),
25	            'path' => $request->path(),
26	            'status' => $response->getStatusCode(),
27	            'duration_ms' => $duration,
28	            'ip' => $request->ip(),
29	            'device_fingerprint' => $request->attributes->get('device_fingerprint_hash'),
30	            'user_id' => $request->user()?->id,
31	        ]);
32	
33	        return $response;
34	    }
