27	
28	        if (!in_array($userRole, $roles, true)) {
29	            if ($request->expectsJson()) {
30	                return response()->json([
31	                    'message' => 'Access denied.',
32	                    'error_code' => 'FORBIDDEN',
33	                ], 403);
34	            }
35	
36	            abort(403, 'Access denied.');
37	        }
38	
39	        return $next($request);
40	    }
