7	class DeviceFingerprintGenerator
8	{
9	    public function __construct(
10	        private readonly string $salt,
11	    ) {}
12	
13	    /**
14	     * Generate a fingerprint hash from device traits.
15	     */
16	    public function generate(string $userAgent, array $screenTraits = []): string
17	    {
18	        $normalized = $this->normalizeTraits($userAgent, $screenTraits);
19	        return hash('sha256', $this->salt . '|' . $normalized);
20	    }
21	
22	    private function normalizeTraits(string $userAgent, array $screenTraits): string
23	    {
24	        $parts = [trim($userAgent)];
25	
26	        // Sort screen traits for consistency
27	        ksort($screenTraits);
28	        foreach ($screenTraits as $key => $value) {
29	            $parts[] = "{$key}:{$value}";
30	        }
31	
32	        return implode('|', $parts);
33	    }
