69	            ->whereNull('acknowledged_by')
70	            ->orderByDesc('created_at')
71	            ->limit(10)
72	            ->get()
73	            ->map(fn ($a) => (array) $a)
74	            ->toArray();
75	
76	        $this->totalOrders = DB::table('orders')->count();
