106	
107	        // Determine sort_order
108	        $maxSort = DB::table('trending_searches')
109	            ->when($this->trendingLocationId !== null, fn ($q) => $q->where('location_id', $this->trendingLocationId))
110	            ->when($this->trendingLocationId === null, fn ($q) => $q->whereNull('location_id'))
111	            ->max('sort_order') ?? 0;
112	
113	        DB::table('trending_searches')->insert([
114	            'term' => $term,
115	            'sort_order' => $maxSort + 1,
116	            'pinned_by' => auth()->id(),
117	            'location_id' => $this->trendingLocationId,
118	            'created_at' => now(),
119	            'updated_at' => now(),
120	        ]);
121	
122	        $this->newTrendingTerm = '';
123	        $this->trendingMessage = "Trending term \"{$term}\" pinned successfully.";
124	        $this->loadTrendingTerms();
125	    }
