6	
7	class PromotionEvaluator
8	{
9	    /**
10	     * Evaluate all active promotions against cart items and find the best offer.
11	     *
12	     * Resolution Tree:
13	     * 1. Evaluate item-level discounts first (BOGO, % off second)
14	     * 2. Evaluate cart-level discounts second (% off total, flat off total)
15	     * 3. Calculate all valid combinations respecting mutual exclusion groups
16	     * 4. Select combination yielding lowest total ("best offer wins")
17	     *
18	     * @param array $cartItems Each: ['sku' => string, 'price' => float, 'quantity' => int, 'name' => string]
19	     * @param array $promotions Each: ['id' => int, 'name' => string, 'type' => string, 'rules' => array, 'exclusion_group' => ?string]
20	     * @param float $cartSubtotal
21	     * @return array|null ['promotion_id' => int, 'name' => string, 'discount_amount' => float, 'description' => string] or null
22	     */
23	    public function evaluate(array $cartItems, array $promotions, float $cartSubtotal): ?array
24	    {
25	        if (empty($cartItems) || empty($promotions)) {
26	            return null;
27	        }
28	
29	        $candidates = [];
30	
31	        // Step 1: Evaluate item-level promotions
32	        foreach ($promotions as $promo) {
33	            $type = PromoType::from($promo['type']);
34	            if (!$type->isItemLevel()) {
35	                continue;
36	            }
37	
38	            $discount = $this->evaluatePromotion($promo, $cartItems, $cartSubtotal);
39	            if ($discount !== null && $discount['discount_amount'] > 0) {
40	                $candidates[] = $discount;
41	            }
42	        }
43	
44	        // Step 2: Evaluate cart-level promotions
45	        foreach ($promotions as $promo) {
46	            $type = PromoType::from($promo['type']);
47	            if (!$type->isCartLevel()) {
48	                continue;
49	            }
50	
51	            $discount = $this->evaluatePromotion($promo, $cartItems, $cartSubtotal);
52	            if ($discount !== null && $discount['discount_amount'] > 0) {
53	                $candidates[] = $discount;
54	            }
55	        }
56	
57	        if (empty($candidates)) {
58	            return null;
59	        }
60	
61	        // Step 3: Filter by mutual exclusion and find best
62	        // Group candidates by exclusion_group
63	        // Within each group, keep only the best
64	        // Then pick the single best across all groups (best offer wins = one promo applied)
65	        $bestByGroup = [];
66	        $ungrouped = [];
67	
68	        foreach ($candidates as $candidate) {
69	            $group = $candidate['exclusion_group'] ?? null;
70	            if ($group) {
71	                if (!isset($bestByGroup[$group]) || $candidate['discount_amount'] > $bestByGroup[$group]['discount_amount']) {
72	                    $bestByGroup[$group] = $candidate;
73	                }
74	            } else {
75	                $ungrouped[] = $candidate;
76	            }
77	        }
78	
79	        // Merge best from each group + ungrouped
80	        $finalists = array_merge(array_values($bestByGroup), $ungrouped);
81	
82	        // Step 4: Select the single best offer (highest discount amount)
83	        usort($finalists, fn ($a, $b) => $b['discount_amount'] <=> $a['discount_amount']);
84	
85	        return $finalists[0] ?? null;
86	    }
87	
88	    private function evaluatePromotion(array $promo, array $cartItems, float $cartSubtotal): ?array
89	    {
90	        $type = PromoType::from($promo['type']);
91	        $rules = $promo['rules'];
92	
93	        $discount = match ($type) {
94	            PromoType::PercentageOff => $this->calcPercentageOff($rules, $cartSubtotal),
95	            PromoType::FlatDiscount => $this->calcFlatDiscount($rules, $cartSubtotal),
96	            PromoType::Bogo => $this->calcBogo($rules, $cartItems),
97	            PromoType::PercentageOffSecond => $this->calcPercentageOffSecond($rules, $cartItems),
98	        };
99	
100	        if ($discount === null || $discount <= 0) {
101	            return null;
102	        }
103	
104	        return [
105	            'promotion_id' => $promo['id'],
106	            'name' => $promo['name'],
107	            'type' => $promo['type'],
108	            'discount_amount' => round($discount, 2),
109	            'exclusion_group' => $promo['exclusion_group'] ?? null,
110	            'description' => $this->buildDescription($promo, $discount),
111	        ];
112	    }
113	
114	    private function calcPercentageOff(array $rules, float $subtotal): ?float
115	    {
116	        $threshold = (float) ($rules['threshold'] ?? 0);
117	        $percentage = (float) ($rules['percentage'] ?? 0);
118	
119	        if ($subtotal < $threshold || $percentage <= 0) {
120	            return null;
121	        }
122	
123	        return round($subtotal * ($percentage / 100), 2);
124	    }
125	
126	    private function calcFlatDiscount(array $rules, float $subtotal): ?float
127	    {
128	        $threshold = (float) ($rules['threshold'] ?? 0);
129	        $amount = (float) ($rules['amount'] ?? 0);
130	
131	        if ($subtotal < $threshold || $amount <= 0) {
132	            return null;
133	        }
134	
135	        return min($amount, $subtotal); // Can't discount more than subtotal
136	    }
137	
138	    private function calcBogo(array $rules, array $cartItems): ?float
139	    {
140	        $targetSkus = $rules['target_skus'] ?? [];
141	        if (empty($targetSkus)) {
142	            return null;
143	        }
144	
145	        // Find qualifying items
146	        $qualifyingItems = [];
147	        foreach ($cartItems as $item) {
148	            if (in_array($item['sku'], $targetSkus)) {
149	                // Expand by quantity
150	                for ($i = 0; $i < $item['quantity']; $i++) {
151	                    $qualifyingItems[] = (float) $item['price'];
152	                }
153	            }
154	        }
155	
156	        if (count($qualifyingItems) < 2) {
157	            return null;
158	        }
159	
160	        // Sort ascending — cheapest item is free
161	        sort($qualifyingItems);
162	
163	        // For every pair, the cheaper one is free
164	        $freeCount = intdiv(count($qualifyingItems), 2);
165	        $discount = 0;
166	        for ($i = 0; $i < $freeCount; $i++) {
167	            $discount += $qualifyingItems[$i];
168	        }
169	
170	        return $discount;
171	    }
172	
173	    private function calcPercentageOffSecond(array $rules, array $cartItems): ?float
174	    {
175	        $targetSkus = $rules['target_skus'] ?? [];
176	        $percentage = (float) ($rules['percentage'] ?? 50);
177	
178	        if (empty($targetSkus)) {
179	            return null;
180	        }
181	
182	        $qualifyingItems = [];
183	        foreach ($cartItems as $item) {
184	            if (in_array($item['sku'], $targetSkus)) {
185	                for ($i = 0; $i < $item['quantity']; $i++) {
186	                    $qualifyingItems[] = (float) $item['price'];
187	                }
188	            }
189	        }
190	
191	        if (count($qualifyingItems) < 2) {
192	            return null;
193	        }
194	
195	        // Sort descending — discount applies to the cheaper (second) item
196	        rsort($qualifyingItems);
197	
198	        // Every second item gets the percentage off
199	        $discount = 0;
200	        for ($i = 1; $i < count($qualifyingItems); $i += 2) {
201	            $discount += $qualifyingItems[$i] * ($percentage / 100);
202	        }
203	
204	        return $discount;
205	    }
206	
207	    private function buildDescription(array $promo, float $discount): string
208	    {
209	        $type = PromoType::from($promo['type']);
210	        $rules = $promo['rules'];
211	
212	        return match ($type) {
213	            PromoType::PercentageOff => "{$rules['percentage']}% off orders over \${$rules['threshold']} — saves \$" . number_format($discount, 2),
214	            PromoType::FlatDiscount => "\${$rules['amount']} off orders over \${$rules['threshold']} — saves \$" . number_format($discount, 2),
215	            PromoType::Bogo => "Buy One Get One Free — saves \$" . number_format($discount, 2),
216	            PromoType::PercentageOffSecond => ($rules['percentage'] ?? 50) . "% off second item — saves \$" . number_format($discount, 2),
217	        };
218	    }
