12	{
13	    private function isPostgres(): bool
14	    {
15	        return DB::getDriverName() === 'pgsql';
16	    }
17	
18	    public function search(SearchQuery $query, array $allergenExclusions = []): array
19	    {
20	        $builder = DB::table('menu_items')
21	            ->join('menu_categories', 'menu_items.menu_category_id', '=', 'menu_categories.id')
22	            ->where('menu_items.is_active', true)
23	            ->where('menu_categories.is_active', true);
24	
25	        // Full-text search
26	        if ($query->hasKeyword()) {
27	            if ($this->isPostgres()) {
28	                $tsQuery = $this->buildTsQuery($query->keyword);
29	                $builder->whereRaw("menu_items.search_vector @@ to_tsquery('english', ?)", [$tsQuery]);
30	            } else {
31	                // SQLite fallback: LIKE-based search
32	                $keyword = '%' . $query->keyword . '%';
33	                $builder->where(function ($q) use ($keyword) {
34	                    $q->where('menu_items.name', 'like', $keyword)
35	                      ->orWhere('menu_items.description', 'like', $keyword);
36	                });
37	            }
38	        }
39	
40	        // Price range
41	        if ($query->priceMin !== null) {
42	            $builder->where('menu_items.price', '>=', $query->priceMin);
43	        }
44	        if ($query->priceMax !== null) {
45	            $builder->where('menu_items.price', '<=', $query->priceMax);
46	        }
47	
48	        // Category filter
49	        if ($query->categoryId !== null) {
50	            $builder->where('menu_items.menu_category_id', $query->categoryId);
51	        }
52	
53	        // Allergen exclusions (negative filters)
54	        foreach ($allergenExclusions as $exclusion) {
55	            $key = $exclusion['key'];
56	            $excludeWhen = $exclusion['exclude_when'];
57	
58	            if ($this->isPostgres()) {
59	                $builder->whereRaw(
60	                    "NOT (menu_items.attributes @> ?::jsonb)",
61	                    [json_encode([$key => $excludeWhen])]
62	                );
63	            } else {
64	                // SQLite fallback: JSON extract
65	                $jsonValue = $excludeWhen ? 'true' : 'false';
66	                $builder->whereRaw(
67	                    "NOT (json_extract(menu_items.attributes, ?) = ?)",
68	                    ['$.' . $key, $jsonValue]
69	                );
70	            }
71	        }
72	
73	        // Get total before pagination
74	        $total = $builder->count();
75	
76	        // Sorting
77	        $selectColumns = [
78	            'menu_items.id',
79	            'menu_items.sku',
80	            'menu_items.name',
81	            'menu_items.description',
82	            'menu_items.price',
83	            'menu_items.tax_category',
84	            'menu_items.attributes',
85	            'menu_items.created_at',
86	            'menu_categories.name as category_name',
87	            'menu_categories.id as category_id',
88	        ];
89	
90	        if ($query->hasKeyword() && $query->sort === 'relevance' && $this->isPostgres()) {
91	            $tsQuery = $this->buildTsQuery($query->keyword);
92	            $selectColumns[] = DB::raw("ts_rank(menu_items.search_vector, to_tsquery('english', " . DB::getPdo()->quote($tsQuery) . ")) as relevance_score");
93	            $builder->orderByDesc('relevance_score');
94	        } else {
95	            match ($query->sort) {
96	                'newest' => $builder->orderByDesc('menu_items.created_at'),
97	                'price_asc' => $builder->orderBy('menu_items.price'),
98	                'price_desc' => $builder->orderByDesc('menu_items.price'),
99	                default => $builder->orderBy('menu_items.name'),
100	            };
101	        }
102	
103	        $items = $builder
104	            ->select($selectColumns)
105	            ->offset(($query->page - 1) * $query->perPage)
106	            ->limit($query->perPage)
107	            ->get()
108	            ->map(function ($item) {
109	                $item->attributes = is_string($item->attributes) ? json_decode($item->attributes, true) : $item->attributes;
110	                return (array) $item;
111	            })
112	            ->toArray();
113	
114	        return [
115	            'items' => $items,
116	            'total' => $total,
117	        ];
118	    }
