123	            ->orderBy('sort_order')
124	            ->limit(20);
125	
126	        if ($locationId !== null) {
127	            $query->where('location_id', $locationId);
128	        }
129	
130	        return $query->pluck('term')->toArray();
131	    }
132	
133	    public function getCategories(): array
134	    {
135	        return DB::table('menu_categories')
136	            ->where('is_active', true)
137	            ->orderBy('sort_order')
138	            ->get(['id', 'name'])
139	            ->map(fn ($c) => (array) $c)
140	            ->toArray();
141	    }
142	
143	    public function findById(int $id): ?array
144	    {
145	        $item = DB::table('menu_items')
146	            ->join('menu_categories', 'menu_items.menu_category_id', '=', 'menu_categories.id')
147	            ->where('menu_items.id', $id)
148	            ->where('menu_items.is_active', true)
149	            ->select([
150	                'menu_items.*',
151	                'menu_categories.name as category_name',
152	            ])
153	            ->first();
154	
155	        if (!$item) {
156	            return null;
