164	    private function buildTsQuery(string $keyword): string
165	    {
166	        $words = preg_split('/\s+/', trim($keyword));
167	        $tsTerms = array_map(fn ($w) => preg_replace('/[^a-zA-Z0-9]/', '', $w) . ':*', $words);
168	        return implode(' & ', array_filter($tsTerms));
