13	class DeviceFingerprintMiddleware
14	{
15	    public function __construct(
16	        private readonly DeviceFingerprintGenerator $generator,
17	    ) {}
18	
19	    public function handle(Request $request, Closure $next): Response
20	    {
21	        $userAgent = $request->userAgent() ?? 'unknown';
22	        $screenTraits = [];
23	
24	        if ($request->hasHeader('X-Screen-Width')) {
25	            $screenTraits['width'] = $request->header('X-Screen-Width');
26	        }
27	        if ($request->hasHeader('X-Screen-Height')) {
28	            $screenTraits['height'] = $request->header('X-Screen-Height');
29	        }
30	        if ($request->hasHeader('X-Screen-Color-Depth')) {
31	            $screenTraits['colorDepth'] = $request->header('X-Screen-Color-Depth');
32	        }
33	
34	        $fingerprintHash = $this->generator->generate($userAgent, $screenTraits);
35	
36	        // Upsert device fingerprint record (race-safe: try insert, handle duplicate)
37	        $fingerprint = DB::table('device_fingerprints')
38	            ->where('fingerprint_hash', $fingerprintHash)
39	            ->first();
40	
41	        if ($fingerprint) {
42	            DB::table('device_fingerprints')
43	                ->where('id', $fingerprint->id)
44	                ->update(['last_seen_at' => now()]);
45	            $fingerprintId = $fingerprint->id;
46	        } else {
47	            try {
48	                $fingerprintId = DB::table('device_fingerprints')->insertGetId([
49	                    'fingerprint_hash' => $fingerprintHash,
50	                    'user_agent' => encrypt($userAgent),
51	                    'screen_traits' => encrypt(json_encode($screenTraits)),
52	                    'first_seen_at' => now(),
53	                    'last_seen_at' => now(),
54	                    'created_at' => now(),
55	                    'updated_at' => now(),
56	                ]);
57	            } catch (\Illuminate\Database\QueryException $e) {
58	                // Duplicate key — another request inserted concurrently; fetch the existing row
59	                $fingerprint = DB::table('device_fingerprints')
60	                    ->where('fingerprint_hash', $fingerprintHash)
61	                    ->first();
62	
63	                if (!$fingerprint) {
64	                    throw $e; // Not a duplicate key error; re-throw
65	                }
66	
67	                DB::table('device_fingerprints')
68	                    ->where('id', $fingerprint->id)
69	                    ->update(['last_seen_at' => now()]);
70	                $fingerprintId = $fingerprint->id;
71	            }
72	        }
73	
74	        $request->attributes->set('device_fingerprint_id', $fingerprintId);
75	        $request->attributes->set('device_fingerprint_hash', $fingerprintHash);
76	
77	        // Check blacklist
78	        $isBlacklisted = DB::table('security_blacklists')
79	            ->where('type', 'device')
80	            ->where('value', $fingerprintHash)
81	            ->where(function ($query) {
82	                $query->whereNull('expires_at')
83	                    ->orWhere('expires_at', '>', now());
84	            })
85	            ->exists();
86	
87	        if ($isBlacklisted) {
88	            DB::table('rule_hit_logs')->insert([
89	                'type' => 'blacklist_block',
90	                'device_fingerprint_id' => $fingerprintId,
91	                'ip_address' => $request->ip(),
92	                'details' => json_encode(['reason' => 'device_blacklisted', 'hash' => $fingerprintHash]),
93	                'created_at' => now(),
94	            ]);
95	
96	            return response()->json([
97	                'message' => 'Access denied.',
98	                'error_code' => 'BLACKLISTED',
99	            ], 403);
100	        }
101	
102	        // Check IP blacklist
103	        $ipBlacklisted = $this->checkIpBlacklist($request->ip());
104	        if ($ipBlacklisted) {
105	            DB::table('rule_hit_logs')->insert([
106	                'type' => 'blacklist_block',
107	                'device_fingerprint_id' => $fingerprintId,
108	                'ip_address' => $request->ip(),
109	                'details' => json_encode(['reason' => 'ip_blacklisted']),
110	                'created_at' => now(),
111	            ]);
112	
113	            return response()->json([
114	                'message' => 'Access denied.',
115	                'error_code' => 'BLACKLISTED',
116	            ], 403);
117	        }
118	
119	        // Check username blacklist (applies to login and authenticated requests)
120	        $username = $request->input('username') ?? auth()->user()?->username ?? null;
121	        if ($username && $this->checkUsernameBlacklist($username)) {
122	            DB::table('rule_hit_logs')->insert([
123	                'type' => 'blacklist_block',
124	                'device_fingerprint_id' => $fingerprintId,
125	                'ip_address' => $request->ip(),
126	                'details' => json_encode(['reason' => 'username_blacklisted', 'username' => $username]),
127	                'created_at' => now(),
128	            ]);
129	
130	            return response()->json([
131	                'message' => 'Access denied.',
132	                'error_code' => 'BLACKLISTED',
133	            ], 403);
134	        }
135	
136	        return $next($request);
137	    }
138	
139	    private function checkIpBlacklist(?string $ip): bool
140	    {
141	        if (!$ip) {
142	            return false;
143	        }
144	
145	        $entries = DB::table('security_blacklists')
146	            ->where('type', 'ip')
147	            ->where(function ($query) {
148	                $query->whereNull('expires_at')
149	                    ->orWhere('expires_at', '>', now());
150	            })
151	            ->get();
152	
153	        foreach ($entries as $entry) {
154	            if ($this->ipMatchesCidr($ip, $entry->value)) {
155	                return true;
156	            }
157	        }
158	
159	        return false;
160	    }
161	
162	    private function checkUsernameBlacklist(string $username): bool
163	    {
164	        return DB::table('security_blacklists')
165	            ->where('type', 'username')
166	            ->where('value', $username)
167	            ->where(function ($query) {
168	                $query->whereNull('expires_at')
169	                    ->orWhere('expires_at', '>', now());
170	            })
171	            ->exists();
172	    }
173	
174	    private function ipMatchesCidr(string $ip, string $cidr): bool
175	    {
176	        if (!str_contains($cidr, '/')) {
177	            return $ip === $cidr;
178	        }
179	
180	        [$subnet, $mask] = explode('/', $cidr);
181	        $mask = (int) $mask;
182	
183	        if ($mask < 0 || $mask > 32) {
184	            return false;
185	        }
186	
187	        $ipLong = ip2long($ip);
188	        $subnetLong = ip2long($subnet);
189	
190	        if ($ipLong === false || $subnetLong === false) {
191	            return false;
192	        }
193	
194	        if ($mask === 0) {
195	            return true; // /0 matches all IPs
196	        }
197	
198	        $maskLong = ~((1 << (32 - $mask)) - 1);
199	        return ($ipLong & $maskLong) === ($subnetLong & $maskLong);
200	    }
