11	use Symfony\Component\HttpFoundation\Response;
12	
13	class RateLimitMiddleware
14	{
15	    public function handle(Request $request, Closure $next, string $action = 'general', int $maxAttempts = 0, int $windowMinutes = 1): Response
16	    {
17	        if ($maxAttempts === 0) {
18	            $maxAttempts = config('harborbite.rate_limits.general_per_minute', 60);
19	        }
20	
21	        // Check whitelist first
22	        $fingerprintHash = $request->attributes->get('device_fingerprint_hash');
23	        if ($fingerprintHash && $this->isWhitelisted('device', $fingerprintHash)) {
24	            return $next($request);
25	        }
26	        if ($request->ip() && $this->isWhitelisted('ip', $request->ip())) {
27	            return $next($request);
28	        }
29	
30	        // Per-device rate limit
31	        if ($fingerprintHash) {
32	            $deviceKey = "rate_limit:device:{$action}:{$fingerprintHash}";
33	            $deviceCount = (int) Cache::get($deviceKey, 0);
34	
35	            if ($deviceCount >= $maxAttempts) {
36	                $this->logRateLimit($request, 'device', $action);
37	                return $this->tooManyRequestsResponse($windowMinutes);
38	            }
39	
40	            Cache::put($deviceKey, $deviceCount + 1, now()->addMinutes($windowMinutes));
41	        }
42	
43	        // Per-IP rate limit
44	        $ip = $request->ip();
45	        if ($ip) {
46	            $ipKey = "rate_limit:ip:{$action}:{$ip}";
47	            $ipCount = (int) Cache::get($ipKey, 0);
48	
49	            if ($ipCount >= $maxAttempts) {
50	                $this->logRateLimit($request, 'ip', $action);
51	                return $this->tooManyRequestsResponse($windowMinutes);
52	            }
53	
54	            Cache::put($ipKey, $ipCount + 1, now()->addMinutes($windowMinutes));
55	        }
56	
57	        return $next($request);
58	    }
59	
60	    private function isWhitelisted(string $type, string $value): bool
61	    {
62	        return DB::table('security_whitelists')
63	            ->where('type', $type)
64	            ->where('value', $value)
65	            ->exists();
66	    }
67	
68	    private function logRateLimit(Request $request, string $limitType, string $action): void
69	    {
70	        try {
71	            DB::table('rule_hit_logs')->insert([
72	                'type' => 'rate_limit',
73	                'device_fingerprint_id' => $request->attributes->get('device_fingerprint_id'),
74	                'ip_address' => $request->ip(),
75	                'details' => json_encode([
76	                    'limit_type' => $limitType,
77	                    'action' => $action,
78	                ]),
79	                'created_at' => now(),
80	            ]);
81	        } catch (\Throwable) {
82	            // Don't let logging failures block the response
83	        }
84	    }
85	
86	    private function tooManyRequestsResponse(int $windowMinutes): Response
87	    {
88	        return response()->json([
89	            'message' => 'Too many requests. Please try again later.',
90	            'error_code' => 'RATE_LIMITED',
91	        ], 429)->withHeaders([
92	            'Retry-After' => $windowMinutes * 60,
93	        ]);
94	    }
95	}
