7	use Illuminate\Console\Command;
8	use Illuminate\Support\Facades\DB;
9	use Illuminate\Support\Facades\Crypt;
10	use Illuminate\Support\Facades\Log;
11	
12	class RotateEncryptionKeyCommand extends Command
13	{
14	    protected $signature = 'harborbite:rotate-key {--dry-run : Show what would be re-encrypted without changes}';
15	    protected $description = 'Re-encrypt all sensitive fields with the current APP_KEY';
16	
17	    public function handle(): int
18	    {
19	        $isDryRun = $this->option('dry-run');
20	        $this->info($isDryRun ? 'DRY RUN — no changes will be made.' : 'Starting key rotation...');
21	
22	        $tables = [
23	            ['table' => 'device_fingerprints', 'columns' => ['user_agent', 'screen_traits']],
24	            ['table' => 'payment_confirmations', 'columns' => ['notes']],
25	            ['table' => 'incident_tickets', 'columns' => ['receipt_reference']],
26	        ];
27	
28	        $totalRows = 0;
29	
30	        foreach ($tables as $config) {
31	            $tableName = $config['table'];
32	            $columns = $config['columns'];
33	
34	            $rows = DB::table($tableName)->get();
35	            $this->line("  Processing {$tableName}: {$rows->count()} rows");
36	
37	            foreach ($rows as $row) {
38	                $updates = [];
39	                foreach ($columns as $col) {
40	                    $value = $row->{$col};
41	                    if ($value === null) {
42	                        continue;
43	                    }
44	
45	                    try {
46	                        // Try to decrypt with current key
47	                        $decrypted = Crypt::decryptString($value);
48	                        // Re-encrypt (will use current APP_KEY)
49	                        $updates[$col] = Crypt::encryptString($decrypted);
50	                    } catch (\Throwable $e) {
51	                        $this->warn("    Could not decrypt {$tableName}.{$col} row {$row->id}: {$e->getMessage()}");
52	                    }
53	                }
54	
55	                if (!empty($updates) && !$isDryRun) {
56	                    DB::table($tableName)->where('id', $row->id)->update($updates);
57	                    $totalRows++;
58	                }
59	            }
60	        }
61	
62	        $verb = $isDryRun ? 'Would re-encrypt' : 'Re-encrypted';
63	        $this->info("{$verb} {$totalRows} rows.");
64	
65	        if (!$isDryRun) {
66	            Log::info('key_rotation_completed', ['rows_affected' => $totalRows]);
67	        }
68	
69	        return self::SUCCESS;
70	    }
71	}
