28	            'cancel_in_preparation' => true,
29	            'cancel_served' => true,
30	            'discount_override' => isset($context['discount_amount']) && $context['discount_amount'] > 20.00,
31	            'settle_ambiguous' => true,
32	            default => false,
33	        };
