56	    public function transitionOrder(int $orderId, string $targetStatus): void
57	    {
58	        $this->errorMessage = null;
59	        $this->successMessage = null;
60	
61	        $order = DB::table('orders')->find($orderId);
62	        if (!$order) {
63	            $this->errorMessage = 'Order not found.';
64	            return;
65	        }
66	
67	        $currentStatus = OrderStatus::from($order->status);
68	        $target = OrderStatus::from($targetStatus);
69	
70	        // Check if step-up is needed
71	        if ($target === OrderStatus::Canceled && $currentStatus->requiresStepUpForCancel()) {
72	            $this->pendingActionOrderId = $orderId;
73	            $this->pendingAction = $targetStatus;
74	            $this->showPinModal = true;
