3	declare(strict_types=1);
4	
5	namespace App\Application\Payment;
6	
7	use App\Domain\Payment\HmacSigner;
8	use App\Domain\Payment\Exceptions\ExpiredNonceException;
9	use App\Domain\Payment\Exceptions\ReplayedNonceException;
10	use App\Domain\Payment\Exceptions\TamperedSignatureException;
11	use Illuminate\Support\Facades\DB;
12	
13	class ConfirmPaymentUseCase
14	{
15	    public function __construct(
16	        private readonly HmacSigner $signer,
17	    ) {}
18	
19	    /**
20	     * @return array{confirmation_id: int, order_status: string, idempotent: bool}
21	     */
22	    public function execute(
23	        string $reference,
24	        string $hmacSignature,
25	        string $nonce,
26	        string $method,
27	        int $confirmedBy,
28	        ?string $notes = null,
29	    ): array {
30	        return DB::transaction(function () use ($reference, $hmacSignature, $nonce, $method, $confirmedBy, $notes) {
31	            $intent = DB::table('payment_intents')
32	                ->where('reference', $reference)
33	                ->lockForUpdate()
34	                ->first();
35	
36	            if (!$intent) {
37	                throw new \RuntimeException('Payment intent not found.');
38	            }
39	
40	            // Idempotency check — if already confirmed, return existing
41	            if ($intent->status === 'confirmed') {
42	                $existingConfirmation = DB::table('payment_confirmations')
43	                    ->where('payment_intent_id', $intent->id)
44	                    ->first();
45	
46	                return [
47	                    'confirmation_id' => $existingConfirmation ? $existingConfirmation->id : 0,
48	                    'order_status' => 'settled',
49	                    'idempotent' => true,
50	                ];
51	            }
52	
53	            if ($intent->status === 'canceled') {
54	                throw new \RuntimeException('Payment intent was canceled.');
55	            }
56	
57	            if ($intent->status === 'failed') {
58	                throw new \RuntimeException('Payment intent has failed.');
59	            }
60	
61	            // Check expiry
62	            if (now()->gt($intent->expires_at)) {
63	                DB::table('payment_intents')
64	                    ->where('id', $intent->id)
65	                    ->update(['status' => 'failed', 'updated_at' => now()]);
66	
67	                throw new ExpiredNonceException(config('harborbite.payment.hmac_expiry_seconds', 300));
68	            }
69	
70	            // Verify HMAC
71	            $this->signer->verify(
72	                $hmacSignature,
73	                [
74	                    'reference' => $reference,
75	                    'amount' => (float) $intent->amount,
76	                    'order_id' => (int) $intent->order_id,
77	                ],
78	                $nonce,
79	                (int) strtotime($intent->created_at),
80	            );
81	
82	            // Mark intent as confirmed
83	            DB::table('payment_intents')
84	                ->where('id', $intent->id)
85	                ->update(['status' => 'confirmed', 'updated_at' => now()]);
86	
87	            // Create confirmation record
88	            $confirmationId = DB::table('payment_confirmations')->insertGetId([
89	                'payment_intent_id' => $intent->id,
90	                'confirmed_by' => $confirmedBy,
91	                'method' => $method,
92	                'notes' => $notes ? encrypt($notes) : null,
93	                'created_at' => now(),
94	            ]);
95	
96	            // Transition order to settled — lock row to prevent race conditions
97	            $order = DB::table('orders')
98	                ->where('id', $intent->order_id)
99	                ->lockForUpdate()
100	                ->first();
101	
102	            if (!$order) {
103	                throw new \RuntimeException('Associated order not found.');
104	            }
105	
106	            if ($order->status !== 'served') {
107	                throw new \RuntimeException(
108	                    "Order cannot be settled: current status is '{$order->status}', expected 'served'."
109	                );
110	            }
111	
112	            DB::table('orders')->where('id', $order->id)->update([
113	                'status' => 'settled',
114	                'settled_by' => $confirmedBy,
115	                'version' => $order->version + 1,
116	                'updated_at' => now(),
117	            ]);
118	
119	            DB::table('order_status_logs')->insert([
120	                'order_id' => $order->id,
121	                'from_status' => $order->status,
122	                'to_status' => 'settled',
123	                'changed_by' => $confirmedBy,
124	                'version_at_change' => $order->version + 1,
125	                'metadata' => json_encode(['payment_reference' => $reference, 'method' => $method]),
126	                'created_at' => now(),
127	            ]);
128	
129	            return [
130	                'confirmation_id' => $confirmationId,
131	                'order_status' => 'settled',
132	                'idempotent' => false,
133	            ];
134	        });
135	    }
136	}
