5	namespace App\Application\Order;
6	
7	use App\Domain\Auth\StepUpVerifier;
8	use App\Domain\Order\OrderStateMachine;
9	use App\Domain\Order\OrderStatus;
10	use App\Domain\Order\Exceptions\InsufficientRoleException;
11	use Illuminate\Support\Facades\DB;
12	
13	class TransitionOrderUseCase
14	{
15	    public function __construct(
16	        private readonly OrderStateMachine $stateMachine,
17	        private readonly StepUpVerifier $stepUpVerifier,
18	    ) {}
19	
20	    /**
21	     * @return array The updated order data
22	     */
23	    public function execute(
24	        int $orderId,
25	        string $targetStatus,
26	        int $expectedVersion,
27	        string $actorRole,
28	        int $actorId,
29	        ?string $managerPin = null,
30	        ?string $managerPinHash = null,
31	        ?string $cancelReason = null,
32	    ): array {
33	        return DB::transaction(function () use ($orderId, $targetStatus, $expectedVersion, $actorRole, $actorId, $managerPin, $managerPinHash, $cancelReason) {
34	            // Lock the order row for update
35	            $order = DB::table('orders')->where('id', $orderId)->lockForUpdate()->first();
36	
37	            if (!$order) {
38	                throw new \RuntimeException("Order not found.");
39	            }
40	
41	            $currentStatus = OrderStatus::from($order->status);
42	            $target = OrderStatus::from($targetStatus);
43	
44	            // Check step-up if needed
45	            $stepUpVerified = false;
46	            if ($target === OrderStatus::Canceled && $currentStatus->requiresStepUpForCancel()) {
47	                if (!$managerPin || !$managerPinHash) {
48	                    throw new InsufficientRoleException(
49	                        role: $actorRole,
50	                        action: "cancel order in {$currentStatus->value} state",
51	                        requiredRoles: ['manager', 'administrator'],
52	                        requiresPin: true,
53	                    );
54	                }
55	                if (!$this->stepUpVerifier->verify($managerPin, $managerPinHash)) {
56	                    throw new InsufficientRoleException(
57	                        role: $actorRole,
58	                        action: "cancel order (incorrect PIN)",
59	                        requiredRoles: ['manager', 'administrator'],
60	                        requiresPin: true,
61	                    );
62	                }
63	                $stepUpVerified = true;
64	
65	                // Log privilege escalation
66	                DB::table('privilege_escalation_logs')->insert([
67	                    'action' => 'cancel_' . $currentStatus->value,
68	                    'order_id' => $orderId,
69	                    'manager_id' => $actorId,
70	                    'manager_pin_hash' => $managerPinHash,
71	                    'reason' => $cancelReason,
72	                    'metadata' => json_encode(['from_status' => $currentStatus->value]),
73	                    'created_at' => now(),
74	                ]);
75	            }
76	
77	            // Execute state machine transition
78	            $newVersion = $this->stateMachine->transition(
79	                $currentStatus,
80	                $target,
81	                (int) $order->version,
82	                $expectedVersion,
83	                $actorRole,
84	                $stepUpVerified,
85	            );
86	
87	            // Update order
88	            $updateData = [
89	                'status' => $target->value,
90	                'version' => $newVersion,
91	                'updated_at' => now(),
92	            ];
93	
94	            // Set actor fields
95	            match ($target) {
96	                OrderStatus::InPreparation => $updateData['confirmed_by'] = $actorId,
97	                OrderStatus::Served => $updateData['prepared_by'] = $actorId,
98	                OrderStatus::Settled => $updateData['settled_by'] = $actorId,
99	                OrderStatus::Canceled => (function () use (&$updateData, $actorId, $cancelReason) {
100	                    $updateData['canceled_by'] = $actorId;
101	                    $updateData['cancel_reason'] = $cancelReason;
102	                })(),
103	                default => null,
104	            };
105	
106	            DB::table('orders')->where('id', $orderId)->update($updateData);
107	
108	            // Lock items when moving to In Preparation
109	            if ($target === OrderStatus::InPreparation) {
110	                DB::table('order_items')
111	                    ->where('order_id', $orderId)
112	                    ->whereNull('locked_at')
113	                    ->update(['locked_at' => now()]);
114	            }
115	
116	            // Log status change
117	            DB::table('order_status_logs')->insert([
118	                'order_id' => $orderId,
119	                'from_status' => $currentStatus->value,
120	                'to_status' => $target->value,
121	                'changed_by' => $actorId,
122	                'version_at_change' => $newVersion,
123	                'metadata' => json_encode([
124	                    'cancel_reason' => $cancelReason,
125	                    'step_up_verified' => $stepUpVerified,
126	                ]),
127	                'created_at' => now(),
128	            ]);
129	
130	            return (array) DB::table('orders')->find($orderId);
131	        });
132	    }
133	}
