declare(strict_types=1);

namespace App\Http\Controllers\Api;

use App\Domain\Cart\CartValidator;
use App\Domain\Cart\TaxCalculator;
use App\Http\Controllers\Controller;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Crypt;
use Illuminate\Support\Facades\DB;

class CartController extends Controller
{
    public function show(Request $request): JsonResponse
    {
        $sessionId = $request->header('X-Session-Id', session()->getId());
        $cart = DB::table('carts')->where('session_id', $sessionId)->first();

        if (!$cart) {
            return response()->json(['data' => null, 'items' => [], 'totals' => null]);
        }

        $items = DB::table('cart_items')
            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
            ->where('cart_items.cart_id', $cart->id)
            ->select([
                'cart_items.id',
                'cart_items.menu_item_id',
                'cart_items.quantity',
                'cart_items.flavor_preference',
                'cart_items.note',
                'cart_items.unit_price_snapshot',
                'menu_items.name',
                'menu_items.price as current_price',
                'menu_items.tax_category',
                'menu_items.sku',
                'menu_items.is_active',
            ])
            ->get()
            ->map(function ($item) {
                $row = (array) $item;
                if ($row['note']) {
                    try {
                        $row['note'] = Crypt::decryptString($row['note']);
                    } catch (\Throwable) {
                        // Already plaintext or corrupt
                    }
                }
                return $row;
            });

        return response()->json([
            'data' => (array) $cart,
            'items' => $items,
        ]);
    }

    public function addItem(Request $request): JsonResponse
    {
        $request->validate([
            'menu_item_id' => 'required|integer',
        ]);

        $itemId = (int) $request->input('menu_item_id');
        $menuItem = DB::table('menu_items')->where('id', $itemId)->where('is_active', true)->first();

        if (!$menuItem) {
            return response()->json(['message' => 'This item is no longer available.'], 404);
        }

        $sessionId = $request->header('X-Session-Id', session()->getId());
        $fingerprintId = $request->attributes->get('device_fingerprint_id');

        $cart = DB::table('carts')->where('session_id', $sessionId)->first();
        if (!$cart) {
            $cartId = DB::table('carts')->insertGetId([
                'session_id' => $sessionId,
                'device_fingerprint_id' => $fingerprintId,
                'created_at' => now(),
                'updated_at' => now(),
            ]);
            $cart = DB::table('carts')->find($cartId);
        }

        $existing = DB::table('cart_items')
            ->where('cart_id', $cart->id)
            ->where('menu_item_id', $itemId)
            ->first();

        if ($existing) {
            $validator = new CartValidator();
            $newQuantity = $existing->quantity + 1;
            $errors = $validator->validateQuantity($newQuantity);
            if (!empty($errors)) {
                return response()->json(['message' => $errors[0]], 422);
            }
            DB::table('cart_items')->where('id', $existing->id)->update([
                'quantity' => $newQuantity,
                'updated_at' => now(),
            ]);
        } else {
            DB::table('cart_items')->insert([
                'cart_id' => $cart->id,
                'menu_item_id' => $itemId,
                'quantity' => 1,
                'flavor_preference' => null,
                'note' => null,
                'unit_price_snapshot' => $menuItem->price,
                'created_at' => now(),
                'updated_at' => now(),
            ]);
        }

        return response()->json(['message' => 'Item added to cart.'], 201);
    }

    public function updateItem(Request $request, int $cartItemId): JsonResponse
    {
        $sessionId = $request->header('X-Session-Id', session()->getId());
        $cart = DB::table('carts')->where('session_id', $sessionId)->first();

        if (!$cart) {
            return response()->json(['message' => 'Cart not found.'], 404);
        }

        $validator = new CartValidator();

        if ($request->has('quantity')) {
            $errors = $validator->validateQuantity((int) $request->input('quantity'));
            if (!empty($errors)) {
                return response()->json(['message' => $errors[0]], 422);
            }
        }

        $update = [];
        if ($request->has('quantity')) {
            $update['quantity'] = (int) $request->input('quantity');
        }
        if ($request->has('note')) {
            $note = $request->input('note');
            $errors = $validator->validateNote($note);
            if (!empty($errors)) {
                return response()->json(['message' => $errors[0]], 422);
            }
            $update['note'] = $note !== '' ? Crypt::encryptString($note) : null;
        }
        if ($request->has('flavor_preference')) {
            $update['flavor_preference'] = $request->input('flavor_preference');
        }

        if (!empty($update)) {
            $update['updated_at'] = now();
            DB::table('cart_items')
                ->where('id', $cartItemId)
                ->where('cart_id', $cart->id)
                ->update($update);
        }

        return response()->json(['message' => 'Cart item updated.']);
    }

    public function removeItem(Request $request, int $cartItemId): JsonResponse
    {
        $sessionId = $request->header('X-Session-Id', session()->getId());
        $cart = DB::table('carts')->where('session_id', $sessionId)->first();

        if (!$cart) {
            return response()->json(['message' => 'Cart not found.'], 404);
        }

        DB::table('cart_items')
            ->where('id', $cartItemId)
            ->where('cart_id', $cart->id)
            ->delete();

        return response()->json(['message' => 'Item removed.']);
    }

    public function clear(Request $request): JsonResponse
    {
        $sessionId = $request->header('X-Session-Id', session()->getId());
        $cart = DB::table('carts')->where('session_id', $sessionId)->first();

        if ($cart) {
            DB::table('cart_items')->where('cart_id', $cart->id)->delete();
        }

        return response()->json(['message' => 'Cart cleared.']);
    }
}
"}

