        $cart = $service->getCart(session()->getId());
        if (!$cart) return;

        $service->updateFlavor($cartItemId, (int) $cart->id, $flavor);
        $this->loadCart();
    }

    public function removeItem(int $cartItemId): void
    {
        $service = app(CartService::class);
        $cart = $service->getCart(session()->getId());
        if (!$cart) return;

        $service->removeItem($cartItemId, (int) $cart->id);
        $this->loadCart();
        $this->dispatch('cart-updated', count: count($this->cartItems));
    }

    public function clearCart(): void
    {
        $service = app(CartService::class);
        $cart = $service->getCart(session()->getId());
        if ($cart) {
            $service->clearCart((int) $cart->id);
        }

        $this->loadCart();
        $this->dispatch('cart-updated', count: 0);
    }

