    {
        $this->errorMessage = null;
        $cart = DB::table('carts')->where('session_id', session()->getId())->first();

        if (!$cart) {
            $this->errorMessage = 'Your cart is empty.';
            return;
        }

        // Check if discount override requires manager PIN
        if ($this->appliedPromotion && !$this->discountOverrideApproved) {
            $discountAmount = (float) $this->appliedPromotion['discount_amount'];
            $verifier = app(StepUpVerifier::class);
            if ($verifier->requiresStepUp('discount_override', ['discount_amount' => $discountAmount])) {
                $this->requiresDiscountOverridePin = true;
                return;
            }
        }

        try {
            $useCase = new CreateOrderUseCase();
            $order = $useCase->execute((int) $cart->id);
            $orderId = (int) $order['id'];

