            if ($this->appliedPromotion) {
                $discount = (float) $this->appliedPromotion['discount_amount'];

                DB::table('applied_promotions')->insert([
                    'order_id' => $orderId,
                    'promotion_id' => $this->appliedPromotion['promotion_id'],
                    'discount_amount' => $discount,
                    'description' => $this->appliedPromotion['description'],
                    'created_at' => now(),
                    'updated_at' => now(),
                ]);

                // Update order totals with discount
                $currentOrder = DB::table('orders')->find($orderId);
                $newTotal = round((float) $currentOrder->subtotal + (float) $currentOrder->tax - $discount, 2);
                DB::table('orders')->where('id', $orderId)->update([
                    'discount' => $discount,
                    'total' => max(0, $newTotal),
                    'updated_at' => now(),
                ]);
            }

            $this->orderPlaced = true;
            $this->orderId = $orderId;
            $this->orderNumber = $order['order_number'];
            $this->trackingToken = $order['tracking_token'];

