    DB::table('orders')->where('id', $orderId)->update(['total' => 999.99]);

    $createIntent = app(\App\Application\Payment\CreatePaymentIntentUseCase::class);
    $intent = $createIntent->execute($orderId);

    // Intent was created with original total, but order total changed
    // Re-create intent after total change so amounts don't match
    DB::table('payment_intents')->where('id', $intent['id'])->update([
        'amount' => 50.00, // Different from order total 999.99
    ]);

