use Illuminate\Support\Facades\Cache;

test('checkout route is rate-limited at 30 per 10 minutes', function () {
    Cache::flush();

    // Make 31 requests to /checkout
    for ($i = 0; $i < 31; $i++) {
        $response = $this->get('/checkout');
    }

    // The 31st should be rate-limited
    $response->assertStatus(429);
    $response->assertHeader('Retry-After');
});

test('checkout under rate limit succeeds', function () {
    Cache::flush();

    // A single request should always succeed
    $this->get('/checkout')->assertStatus(200);
});
"}

