14	class ConfirmPaymentUseCase
15	{
16	    public function __construct(
17	        private readonly HmacSigner $signer,
18	        private readonly StepUpVerifier $stepUpVerifier,
19	    ) {}
20	
21	    /**
22	     * @return array{confirmation_id: int, order_status: string, idempotent: bool}
23	     */
24	    public function execute(
25	        string $reference,
26	        string $hmacSignature,
27	        string $nonce,
28	        string $method,
29	        int $confirmedBy,
30	        ?string $notes = null,
31	        ?string $managerPin = null,
32	        ?string $managerPinHash = null,
33	    ): array {
34	        return DB::transaction(function () use ($reference, $hmacSignature, $nonce, $method, $confirmedBy, $notes, $managerPin, $managerPinHash) {
35	            $intent = DB::table('payment_intents')
36	                ->where('reference', $reference)
37	                ->lockForUpdate()
38	                ->first();
39	
40	            if (!$intent) {
41	                throw new \RuntimeException('Payment intent not found.');
42	            }
43	
44	            // Idempotency check — if already confirmed, return existing
45	            if ($intent->status === 'confirmed') {
46	                $existingConfirmation = DB::table('payment_confirmations')
47	                    ->where('payment_intent_id', $intent->id)
48	                    ->first();
49	
50	                return [
51	                    'confirmation_id' => $existingConfirmation ? $existingConfirmation->id : 0,
52	                    'order_status' => 'settled',
53	                    'idempotent' => true,
54	                ];
55	            }
56	
57	            if ($intent->status === 'canceled') {
58	                throw new \RuntimeException('Payment intent was canceled.');
59	            }
60	
61	            if ($intent->status === 'failed') {
62	                throw new \RuntimeException('Payment intent has failed.');
63	            }
64	
65	            // Check expiry
66	            if (now()->gt($intent->expires_at)) {
67	                DB::table('payment_intents')
68	                    ->where('id', $intent->id)
69	                    ->update(['status' => 'failed', 'updated_at' => now()]);
70	
71	                throw new ExpiredNonceException(config('harborbite.payment.hmac_expiry_seconds', 300));
72	            }
73	
74	            // Verify HMAC
75	            $this->signer->verify(
76	                $hmacSignature,
77	                [
78	                    'reference' => $reference,
79	                    'amount' => (float) $intent->amount,
80	                    'order_id' => (int) $intent->order_id,
81	                ],
82	                $nonce,
83	                (int) strtotime($intent->created_at),
84	            );
85	
86	            // Mark intent as confirmed
87	            DB::table('payment_intents')
88	                ->where('id', $intent->id)
89	                ->update(['status' => 'confirmed', 'updated_at' => now()]);
90	
91	            // Create confirmation record
92	            $confirmationId = DB::table('payment_confirmations')->insertGetId([
93	                'payment_intent_id' => $intent->id,
94	                'confirmed_by' => $confirmedBy,
95	                'method' => $method,
96	                'notes' => $notes ? encrypt($notes) : null,
97	                'created_at' => now(),
98	            ]);
99	
100	            // Transition order to settled — lock row to prevent race conditions
101	            $order = DB::table('orders')
102	                ->where('id', $intent->order_id)
103	                ->lockForUpdate()
104	                ->first();
105	
106	            if (!$order) {
107	                throw new \RuntimeException('Associated order not found.');
108	            }
109	
110	            if (!in_array($order->status, ['served', 'in_preparation'])) {
111	                throw new \RuntimeException(
112	                    "Order cannot be settled: current status is '{$order->status}', expected 'served' or 'in_preparation'."
113	                );
114	            }
115	
116	            // Check for ambiguous settlement (amount mismatch or non-served status)
117	            $isAmbiguous = abs((float) $intent->amount - (float) $order->total) > 0.01
118	                || $order->status !== 'served';
119	
120	            if ($isAmbiguous) {
121	                if (!$managerPin || !$managerPinHash) {
122	                    throw new \RuntimeException(
123	                        'Ambiguous settlement requires manager PIN approval (amount mismatch or non-standard status).'
124	                    );
125	                }
