12	use Illuminate\Support\Facades\DB;
13	use Livewire\Component;
14	
15	class CheckoutFlow extends Component
16	{
17	    public ?array $cartSummary = null;
18	    public ?array $appliedPromotion = null;
19	    public bool $orderPlaced = false;
20	    public ?int $orderId = null;
21	    public ?string $orderNumber = null;
22	    public ?string $trackingToken = null;
23	    public ?string $errorMessage = null;
24	
25	    // Manager PIN step-up for discount override > $20
26	    public bool $requiresDiscountOverridePin = false;
27	    public string $discountOverridePin = '';
28	    public bool $discountOverrideApproved = false;
29	
30	    public function mount(): void
31	    {
32	        $this->loadCartSummary();
33	    }
34	
35	    public function approveDiscountOverride(): void
36	    {
37	        $this->errorMessage = null;
38	        $user = auth()->user();
39	
40	        if (!$user || !$user->manager_pin) {
41	            $this->errorMessage = 'No manager PIN configured for your account.';
42	            return;
43	        }
44	
45	        $verifier = app(StepUpVerifier::class);
46	        if (!$verifier->verify($this->discountOverridePin, $user->manager_pin)) {
47	            $this->errorMessage = 'Incorrect manager PIN.';
48	            return;
49	        }
50	
51	        // Log the privilege escalation
52	        DB::table('privilege_escalation_logs')->insert([
53	            'action' => 'discount_override',
54	            'order_id' => null,
55	            'manager_id' => $user->id,
56	            'manager_pin_hash' => $user->manager_pin,
57	            'reason' => 'Discount over $20.00 approved',
58	            'metadata' => json_encode([
59	                'discount_amount' => $this->appliedPromotion['discount_amount'] ?? 0,
60	            ]),
61	            'created_at' => now(),
62	        ]);
63	
64	        $this->discountOverrideApproved = true;
65	        $this->requiresDiscountOverridePin = false;
66	        $this->discountOverridePin = '';
67	        $this->errorMessage = null;
68	    }
69	
70	    public function cancelDiscountOverride(): void
71	    {
72	        $this->requiresDiscountOverridePin = false;
73	        $this->discountOverridePin = '';
74	    }
75	
76	    public function placeOrder(): void
77	    {
78	        $this->errorMessage = null;
79	        $cartService = app(CartService::class);
80	        $cart = $cartService->getCart(session()->getId());
81	
82	        if (!$cart) {
83	            $this->errorMessage = 'Your cart is empty.';
84	            return;
85	        }
86	
87	        // Check if discount override requires manager PIN
88	        if ($this->appliedPromotion && !$this->discountOverrideApproved) {
89	            $discountAmount = (float) $this->appliedPromotion['discount_amount'];
90	            $verifier = app(StepUpVerifier::class);
91	            if ($verifier->requiresStepUp('discount_override', ['discount_amount' => $discountAmount])) {
92	                $this->requiresDiscountOverridePin = true;
93	                return;
94	            }
95	        }
96	
97	        try {
98	            $createOrder = new CreateOrderUseCase();
99	            $order = $createOrder->execute((int) $cart->id);
100	            $orderId = (int) $order['id'];
101	
102	            // Apply promotion via use case
103	            if ($this->appliedPromotion) {
104	                $applyPromo = new ApplyPromotionUseCase();
105	                $applyPromo->execute(
106	                    $orderId,
107	                    (int) $this->appliedPromotion['promotion_id'],
108	                    (float) $this->appliedPromotion['discount_amount'],
109	                    $this->appliedPromotion['description'],
110	                );
111	            }
112	
113	            $this->orderPlaced = true;
114	            $this->orderId = $orderId;
115	            $this->orderNumber = $order['order_number'];
116	            $this->trackingToken = $order['tracking_token'];
117	
118	            // Clear cart via service
119	            $cartService->clearCart((int) $cart->id);
120	            $this->dispatch('cart-updated', count: 0);
121	        } catch (\Throwable $e) {
122	            $this->errorMessage = $e->getMessage();
123	        }
124	    }
125	
126	    private function loadCartSummary(): void
127	    {
128	        $cartService = app(CartService::class);
129	        $cart = $cartService->getCart(session()->getId());
130	        if (!$cart) {
131	            $this->cartSummary = null;
132	            return;
133	        }
134	
135	        $items = DB::table('cart_items')
136	            ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
137	            ->where('cart_items.cart_id', $cart->id)
138	            ->select(['cart_items.*', 'menu_items.name', 'menu_items.sku', 'menu_items.tax_category'])
139	            ->get();
140	
141	        if ($items->isEmpty()) {
142	            $this->cartSummary = null;
143	            return;
144	        }
145	
146	        $subtotal = 0;
147	        $itemList = [];
148	        $promoItems = [];
149	
150	        foreach ($items as $item) {
151	            $lineTotal = round((float) $item->unit_price_snapshot * $item->quantity, 2);
152	            $subtotal += $lineTotal;
153	            $itemList[] = [
154	                'name' => $item->name,
155	                'sku' => $item->sku,
156	                'quantity' => $item->quantity,
157	                'unit_price' => (float) $item->unit_price_snapshot,
158	                'line_total' => $lineTotal,
159	            ];
160	            $promoItems[] = [
161	                'sku' => $item->sku,
162	                'price' => (float) $item->unit_price_snapshot,
163	                'quantity' => $item->quantity,
164	                'name' => $item->name,
165	            ];
166	        }
167	
168	        $subtotal = round($subtotal, 2);
169	
170	        // Evaluate promotions
171	        $this->appliedPromotion = null;
172	        $promotions = DB::table('promotions')
173	            ->where('is_active', true)
174	            ->where('starts_at', '<=', now())
175	            ->where('ends_at', '>=', now())
176	            ->get()
177	            ->map(function ($p) {
178	                $arr = (array) $p;
179	                $arr['rules'] = json_decode($arr['rules'], true);
180	                return $arr;
181	            })
182	            ->toArray();
183	
184	        if (!empty($promotions)) {
185	            $evaluator = app(PromotionEvaluator::class);
186	            $this->appliedPromotion = $evaluator->evaluate($promoItems, $promotions, $subtotal);
187	
188	            // Attach time window in local time for display
189	            if ($this->appliedPromotion) {
190	                $localTz = config('harborbite.timezone', 'America/Chicago');
191	                $matchedPromo = collect($promotions)->firstWhere('id', $this->appliedPromotion['promotion_id']);
192	                if ($matchedPromo) {
193	                    $startsAt = \Carbon\Carbon::parse($matchedPromo['starts_at'])->setTimezone($localTz);
194	                    $endsAt = \Carbon\Carbon::parse($matchedPromo['ends_at'])->setTimezone($localTz);
195	                    $this->appliedPromotion['time_window'] = $startsAt->format('m/d/Y g:i A') . ' – ' . $endsAt->format('m/d/Y g:i A');
196	                }
197	            }
198	        }
199	
200	        $discount = $this->appliedPromotion ? (float) $this->appliedPromotion['discount_amount'] : 0;
201	
202	        $this->cartSummary = [
203	            'items' => $itemList,
204	            'subtotal' => $subtotal,
205	            'discount' => $discount,
206	            'total_after_discount' => round($subtotal - $discount, 2),
207	            'item_count' => count($itemList),
208	        ];
209	    }
210	
211	    public function render()
212	    {
213	        return view('livewire.checkout.checkout-flow');
214	    }
215	}
