            }
        }

        $discount = $this->appliedPromotion ? (float) $this->appliedPromotion['discount_amount'] : 0;

        $this->cartSummary = [
            'items' => $itemList,
            'subtotal' => $subtotal,
            'discount' => $discount,
            'total_after_discount' => round($subtotal - $discount, 2),
