14	    public function execute(int $cartId): array
15	    {
16	        return DB::transaction(function () use ($cartId) {
17	            $cart = DB::table('carts')->find($cartId);
18	            if (!$cart) {
19	                throw new \RuntimeException("Cart not found.");
20	            }
21	
22	            $cartItems = DB::table('cart_items')
23	                ->join('menu_items', 'cart_items.menu_item_id', '=', 'menu_items.id')
24	                ->where('cart_items.cart_id', $cartId)
25	                ->where('menu_items.is_active', true)
26	                ->select([
27	                    'cart_items.*',
28	                    'menu_items.name',
29	                    'menu_items.sku',
30	                    'menu_items.price as current_price',
31	                    'menu_items.tax_category',
32	                ])
33	                ->get();
34	
35	            if ($cartItems->isEmpty()) {
36	                throw new \RuntimeException("Cart is empty.");
37	            }
38	
39	            // Calculate totals
40	            $subtotal = 0;
41	            $taxItems = [];
42	            foreach ($cartItems as $item) {
43	                $lineTotal = round((float) $item->unit_price_snapshot * $item->quantity, 2);
44	                $subtotal += $lineTotal;
45	                $taxItems[] = [
46	                    'name' => $item->name,
47	                    'price' => (float) $item->unit_price_snapshot,
48	                    'quantity' => $item->quantity,
49	                    'tax_category' => $item->tax_category,
50	                ];
51	            }
52	
53	            $taxRules = DB::table('tax_rules')
54	                ->whereDate('effective_from', '<=', now())
55	                ->where(fn ($q) => $q->whereNull('effective_to')->orWhereDate('effective_to', '>=', now()))
56	                ->get(['category', 'rate'])
57	                ->map(fn ($r) => (array) $r)
58	                ->toArray();
59	
60	            $taxCalc = new TaxCalculator($taxRules);
61	            $tax = $taxCalc->calculateCartTax($taxItems);
62	            $total = round($subtotal + $tax, 2);
63	
64	            // Generate order number and tracking token
65	            $orderNumber = 'HB-' . strtoupper(Str::random(8));
66	            $trackingToken = bin2hex(random_bytes(32));
67	
68	            // Create order
69	            $orderId = DB::table('orders')->insertGetId([
70	                'order_number' => $orderNumber,
71	                'tracking_token' => $trackingToken,
72	                'cart_id' => $cartId,
73	                'status' => 'pending_confirmation',
74	                'version' => 1,
75	                'subtotal' => $subtotal,
76	                'tax' => $tax,
77	                'discount' => 0,
78	                'total' => $total,
79	                'created_at' => now(),
80	                'updated_at' => now(),
81	            ]);
82	
83	            // Create order items (snapshot) — notes stay encrypted from cart
84	            foreach ($cartItems as $item) {
85	                $note = $item->note;
86	                // If note is plaintext (legacy), encrypt it
87	                if ($note !== null) {
88	                    try {
89	                        Crypt::decryptString($note);
90	                        // Already encrypted, keep as-is
91	                    } catch (\Throwable) {
92	                        $note = Crypt::encryptString($note);
93	                    }
94	                }
95	
96	                DB::table('order_items')->insert([
97	                    'order_id' => $orderId,
98	                    'menu_item_id' => $item->menu_item_id,
99	                    'item_name' => $item->name,
100	                    'item_sku' => $item->sku,
101	                    'unit_price' => $item->unit_price_snapshot,
102	                    'quantity' => $item->quantity,
103	                    'tax_category' => $item->tax_category,
104	                    'flavor_preference' => $item->flavor_preference,
105	                    'note' => $note,
106	                    'locked_at' => null,
107	                    'created_at' => now(),
108	                    'updated_at' => now(),
109	                ]);
110	            }
111	
112	            // Log initial status
113	            DB::table('order_status_logs')->insert([
114	                'order_id' => $orderId,
115	                'from_status' => '',
116	                'to_status' => 'pending_confirmation',
117	                'changed_by' => null,
118	                'version_at_change' => 1,
119	                'metadata' => json_encode(['source' => 'kiosk', 'cart_id' => $cartId]),
120	                'created_at' => now(),
121	            ]);
122	
123	            // Track analytics event
124	            (new \App\Application\Analytics\TrackEventUseCase())->execute(
125	                eventType: 'order_placed',
126	                sessionId: $cart->session_id,
127	                payload: ['order_id' => $orderId, 'total' => $total],
128	            );
129	
130	            return (array) DB::table('orders')->find($orderId);
131	        });
132	    }
133	}
