10	class ReconciliationQueue extends Component
11	{
12	    public array $tickets = [];
13	    public string $filterStatus = 'open';
14	
15	    // Resolve form
16	    public ?int $resolvingTicketId = null;
17	    public string $reasonCode = 'cash_verified';
18	    public string $receiptReference = '';
19	
20	    public ?string $message = null;
21	    public ?string $error = null;
22	
23	    public array $reasonCodes = [
24	        'cash_verified' => 'Cash Verified',
25	        'card_receipt_matched' => 'Card Receipt Matched',
26	        'pos_system_confirmed' => 'POS System Confirmed',
27	        'other' => 'Other',
28	    ];
29	
30	    public function mount(): void
31	    {
32	        $this->loadTickets();
33	    }
34	
35	    public function updatedFilterStatus(): void
36	    {
37	        $this->loadTickets();
38	    }
39	
40	    public function openResolve(int $ticketId): void
41	    {
42	        $this->resolvingTicketId = $ticketId;
43	        $this->reasonCode = 'cash_verified';
44	        $this->receiptReference = '';
45	    }
46	
47	    public function cancelResolve(): void
48	    {
49	        $this->resolvingTicketId = null;
50	    }
51	
52	    public function resolveTicket(): void
53	    {
54	        $this->error = null;
55	        $this->message = null;
56	
57	        if (!$this->resolvingTicketId) {
58	            $this->error = 'No ticket selected.';
59	            return;
60	        }
61	
62	        if (!array_key_exists($this->reasonCode, $this->reasonCodes)) {
63	            $this->error = 'Invalid reason code.';
64	            return;
65	        }
66	
67	        $ticket = DB::table('incident_tickets')->find($this->resolvingTicketId);
68	        if (!$ticket || $ticket->status !== 'open') {
69	            $this->error = 'Ticket not found or already resolved.';
70	            return;
71	        }
72	
73	        DB::table('incident_tickets')->where('id', $this->resolvingTicketId)->update([
74	            'status' => 'resolved',
75	            'resolution_reason_code' => $this->reasonCode,
76	            'receipt_reference' => trim($this->receiptReference) ?: null,
77	            'resolved_by' => auth()->id(),
78	            'resolved_at' => now(),
79	            'updated_at' => now(),
80	        ]);
81	
82	        // If there's an associated payment_intent in reconciling status, mark it confirmed
83	        if ($ticket->payment_intent_id) {
84	            DB::table('payment_intents')
85	                ->where('id', $ticket->payment_intent_id)
86	                ->where('status', 'reconciling')
87	                ->update([
88	                    'status' => 'confirmed',
89	                    'updated_at' => now(),
90	                ]);
91	        }
92	
93	        $this->message = "Ticket #{$this->resolvingTicketId} resolved.";
94	        $this->resolvingTicketId = null;
95	        $this->loadTickets();
96	    }
97	
98	    public function dismissTicket(int $id): void
