    public function applyDiscountOverride(): void
    {
        $this->errorMessage = null;

        if ($this->discountAmount <= 0) {
            $this->errorMessage = 'Discount amount must be positive.';
            return;
        }

        $user = auth()->user();
        $verifier = app(\App\Domain\Auth\StepUpVerifier::class);

        // Require manager PIN for discounts > $20
        if ($verifier->requiresStepUp('discount_override', ['discount_amount' => $this->discountAmount])) {
            if (!$this->discountPin) {
                $this->errorMessage = 'Manager PIN required for discounts over $20.00.';
                return;
            }
            if (!$user->manager_pin || !$verifier->verify($this->discountPin, $user->manager_pin)) {
                $this->errorMessage = 'Incorrect manager PIN.';
                return;
            }
        }

        $order = DB::table('orders')->find($this->discountOrderId);
        if (!$order) {
            $this->errorMessage = 'Order not found.';
            return;
        }

        $discount = round($this->discountAmount, 2);
        $newTotal = round((float) $order->subtotal + (float) $order->tax - $discount, 2);

        DB::table('orders')->where('id', $order->id)->update([
            'discount' => $discount,
            'total' => max(0, $newTotal),
            'updated_at' => now(),
        ]);

        // Log privilege escalation
        DB::table('privilege_escalation_logs')->insert([
            'action' => 'discount_override',
            'order_id' => $order->id,
            'manager_id' => $user->id,
            'manager_pin_hash' => $user->manager_pin,
            'reason' => $this->discountReason ?: "Manual discount of \${$discount}",
            'metadata' => json_encode([
                'discount_amount' => $discount,
                'original_total' => (float) $order->total,
                'new_total' => max(0, $newTotal),
            ]),
            'created_at' => now(),
        ]);

        $this->successMessage = "Discount of \${$discount} applied to order #{$order->order_number}.";
        $this->showDiscountModal = false;
        $this->discountOrderId = null;
        $this->loadOrders();
    }

    public function dismissConflict(): void
    {"}

