    {
        // Resolve limits from config when not explicitly provided in middleware params
        if ($maxAttempts === 0 || $windowMinutes === 0) {
            $configMap = [
                'registration' => ['max' => config('harborbite.rate_limits.registrations_per_hour', 10), 'window' => 60],
                'checkout' => ['max' => config('harborbite.rate_limits.checkouts_per_10_min', 30), 'window' => 10],
                'login' => ['max' => 10, 'window' => 1],
                'general' => ['max' => config('harborbite.rate_limits.general_per_minute', 60), 'window' => 1],
            ];

            $resolved = $configMap[$action] ?? $configMap['general'];
            if ($maxAttempts === 0) {
                $maxAttempts = $resolved['max'];
            }
            if ($windowMinutes === 0) {
                $windowMinutes = $resolved['window'];
            }
        }"}

