use App\Models\User;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Hash;

beforeEach(function () {
    DB::table('users')->insert([
        ['id' => 1, 'name' => 'Admin', 'username' => 'admin', 'password' => Hash::make('admin123'), 'manager_pin' => null, 'role' => 'administrator', 'is_active' => true, 'created_at' => now(), 'updated_at' => now()],
        ['id' => 2, 'name' => 'Cashier', 'username' => 'cashier', 'password' => Hash::make('cashier123'), 'manager_pin' => null, 'role' => 'cashier', 'is_active' => true, 'created_at' => now(), 'updated_at' => now()],
    ]);
});

test('whitelisted username bypasses rate limiting on authenticated API route', function () {
    Cache::flush();

    // Whitelist the cashier username
    DB::table('security_whitelists')->insert([
        'type' => 'username',
        'value' => 'cashier',
        'reason' => 'Trusted user',
        'created_by' => 1,
        'created_at' => now(),
        'updated_at' => now(),
    ]);

    // Seed data for order transitions
    DB::table('menu_categories')->insert([
        ['id' => 1, 'name' => 'Test', 'sort_order' => 1, 'is_active' => true, 'created_at' => now(), 'updated_at' => now()],
    ]);
    DB::table('menu_items')->insert([
        ['id' => 1, 'sku' => 'T-001', 'menu_category_id' => 1, 'name' => 'Burger', 'description' => 'Test', 'price' => 10.00, 'tax_category' => 'hot_prepared', 'is_active' => true, 'attributes' => '{}', 'created_at' => now(), 'updated_at' => now()],
    ]);
    DB::table('tax_rules')->insert([
        ['category' => 'hot_prepared', 'rate' => 0.0825, 'effective_from' => '2026-01-01', 'effective_to' => null, 'created_at' => now(), 'updated_at' => now()],
    ]);

    $user = User::find(2);

    // Make many authenticated requests — the global rate limit (60/min) would normally trigger
    // but username whitelist should bypass it
    for ($i = 0; $i < 65; $i++) {
        $response = $this->actingAs($user)->getJson('/api/cart');
    }

    // Should still succeed — username whitelist bypasses rate limit
    $response->assertStatus(200);
});

test('non-whitelisted username is still rate-limited', function () {
    Cache::flush();

    // Do NOT whitelist the cashier
    // The login route has rate-limit:login middleware (10/min from config)
    for ($i = 0; $i < 11; $i++) {
        $response = $this->get('/login');
    }

    // Should be rate-limited
    $response->assertStatus(429);
});

test('admin can add and remove username whitelist entries via UI', function () {
    \Livewire\Livewire::test(\App\Livewire\Admin\SecurityRulesManager::class)
        ->set('wlType', 'username')
        ->set('wlValue', 'trusted_user')
        ->set('wlReason', 'VIP kiosk operator')
        ->call('addWhitelist');

    $entry = DB::table('security_whitelists')
        ->where('type', 'username')
        ->where('value', 'trusted_user')
        ->first();

    expect($entry)->not->toBeNull();
    expect($entry->reason)->toBe('VIP kiosk operator');
});

test('admin can manage banned words with cache invalidation', function () {
    $component = \Livewire\Livewire::test(\App\Livewire\Admin\SecurityRulesManager::class);

    // Add
    $component->set('newBannedWord', 'testbadword')
        ->call('addBannedWord');

    $word = DB::table('banned_words')->where('word', 'testbadword')->first();
    expect($word)->not->toBeNull();

    // Cache should be cleared
    expect(Cache::has('banned_words'))->toBeFalse();

    // Remove
    $component->call('removeBannedWord', $word->id);
    expect(DB::table('banned_words')->where('word', 'testbadword')->exists())->toBeFalse();
});

test('duplicate banned word is rejected', function () {
    DB::table('banned_words')->insert([
        'word' => 'existing',
        'created_at' => now(),
        'updated_at' => now(),
    ]);

    \Livewire\Livewire::test(\App\Livewire\Admin\SecurityRulesManager::class)
        ->set('newBannedWord', 'existing')
        ->call('addBannedWord')
        ->assertSet('error', 'Word already banned.');
});
"}

